import { initAos, initStaggeredAos } from './plugins/aos';
import { initLenis } from './plugins/lenis';
import { getLenis } from './plugins/lenis';

ScrollTrigger.defaults({
  markers: false,
});

function initApp() {
  // const mm = gsap.matchMedia();
  const windowWidth = window.innerWidth;
  const mobileBreakpoint = 768;
  const isMobile = windowWidth <= mobileBreakpoint;

  initLenis();
  window.lenis = getLenis();
  // showHideGrid();
  //reusable functions
  // initFadeEatchWordOnScroll();
  // createSplitText();
  initAos();
  initStaggeredAos();

  // main
  navColorChange();
  initFaqAccordion();
  customAccordion();
  initLoad();

  //about hazany
  initExperienceHazany();

  // keloid
  howAnimation();

  if (!isMobile) {
    // Desktop specific code here
    initDropdown();
    tabsCustom();
  }

  if (isMobile) {
    // Mobile specific code here
    initNavbarDropdown();
    navMobile();
    tabsAccordion();
  }
}

function initFaqAccordion(containerSelector = '.faq-content', allowMultipleOpen = false) {
  const container = document.querySelectorAll(containerSelector);
  if (!container.length) return;

  container.forEach((container) => {
    const items = container.querySelectorAll('.faq-item');

    items.forEach((item, index) => {
      const text = item.querySelector('.faq-item-content');
      const icon = item.querySelector('.icon');
      if (!text || !icon) return;

      // Set ikon awal (kalau pakai rotate)
      gsap.set(icon, { rotate: 180 });
      gsap.set(text, { height: 0, autoAlpha: 0 });
      ScrollTrigger.refresh(); // Refresh ScrollTrigger untuk memastikan posisi benar

      const tl = gsap.timeline({ paused: true, reversed: true });

      tl.to(text, {
        height: 'auto',
        duration: 0.25,
        ease: 'none',
      })
        .to(
          text,
          {
            autoAlpha: 1,
            duration: 0.15,
            ease: 'none',
          },
          0
        )
        .to(
          icon,
          {
            rotate: 0,
            duration: 0.15,
            ease: 'none',
          },
          0
        ); // ikon animasi dimulai bersamaan

      item._accordionTimeline = tl;

      // Event klik
      item.addEventListener('click', (e) => {
        if (e.target.closest('.faq-item-content')) return;

        const isOpen = !tl.reversed();

        if (!allowMultipleOpen) {
          items.forEach((other) => {
            if (other !== item && !other._accordionTimeline.reversed()) {
              other.classList.remove('is-active');
              other._accordionTimeline.reverse();
            }
          });
        }

        if (isOpen) {
          item.classList.remove('is-active');
          tl.reverse();
        } else {
          item.classList.add('is-active');
          tl.play();
        }
      });

      // === Auto open item pertama ===
      if (index === 0) {
        item.classList.add('is-active');
        tl.play(0);
        ScrollTrigger.refresh(); // Refresh ScrollTrigger setelah membuka item pertama
      }
    });
  });
}

function customAccordion(containerSelector = '[data-accordion]', allowMultipleOpen = false) {
  const container = document.querySelector(containerSelector);
  if (!container) return;

  const items = container.querySelectorAll('[accordion-item]');

  items.forEach((item, index) => {
    const text = item.querySelector('[accordion-content]');
    if (!text) return;

    // Set ikon awal (kalau pakai rotate)
    gsap.set(text, { height: 0, autoAlpha: 0 });
    ScrollTrigger.refresh(); // Refresh ScrollTrigger untuk memastikan posisi benar

    const tl = gsap.timeline({ paused: true, reversed: true });

    tl.to(text, {
      height: 'auto',
      duration: 0.25,
      ease: 'none',
    }).to(
      text,
      {
        autoAlpha: 1,
        duration: 0.15,
        ease: 'none',
      },
      0
    );

    item._accordionTimeline = tl;

    // Event klik
    item.addEventListener('click', (e) => {
      if (e.target.closest('[accordion-content]')) return;

      const isOpen = !tl.reversed();

      if (!allowMultipleOpen) {
        items.forEach((other) => {
          if (other !== item && !other._accordionTimeline.reversed()) {
            other.classList.remove('is-active');
            other._accordionTimeline.reverse();
          }
        });
      }

      if (isOpen) {
        item.classList.remove('is-active');
        tl.reverse();
      } else {
        item.classList.add('is-active');
        tl.play();
      }
    });

    // === Auto open item pertama ===
    if (index === 0) {
      item.classList.add('is-active');
      tl.play(0);
      ScrollTrigger.refresh(); // Refresh ScrollTrigger setelah membuka item pertama
    }
  });
}

function initLoad() {
  const wrapper = document.querySelector('[data-load-wrapper]');
  if (!wrapper) return;

  const items = wrapper.querySelectorAll('[load-item]');
  if (!items.length) return;

  const tl = gsap.timeline();
  gsap.set(items, { autoAlpha: 0, y: 20 });

  tl.to(items, {
    autoAlpha: 1,
    y: 0,
    duration: 0.8,
    ease: 'power2.out',
    stagger: {
      each: 0.1,
    },
  });
}

function navColorChange() {
  const navbar = document.querySelector('.navbar');
  const navMobile = document.querySelector('.nav-mobile');
  const sections = document.querySelectorAll('[dark-section]');

  if (!navbar || !navMobile || !sections.length) return;

  const navHeight = navbar.offsetHeight / 2;

  sections.forEach((section) => {
    ScrollTrigger.create({
      trigger: section,
      start: `top ${navHeight}px`,
      end: `bottom ${navHeight}px`,

      onEnter: () => {
        navbar.classList.remove('is-dark');
        navMobile.classList.remove('is-dark');
      },

      onEnterBack: () => {
        navbar.classList.remove('is-dark');
        navMobile.classList.remove('is-dark');
      },

      onLeave: () => {
        navbar.classList.add('is-dark');
        navMobile.classList.add('is-dark');
      },

      onLeaveBack: () => {
        navbar.classList.add('is-dark');
        navMobile.classList.add('is-dark');
      },
    });
  });
}

function initNavbarDropdown() {
  const navMob = document.querySelector('.nav-mobile');
  if (!navMob) return;

  const inner = navMob.querySelector('.nav-mobile-inner');
  const main = navMob.querySelector('.nav-mobile-main');

  const targets = navMob.querySelectorAll('[data-dd-target]');
  const panels = navMob.querySelectorAll('[data-dd-panel]');
  const backBtns = navMob.querySelectorAll('.nav-back-button');

  // OPEN SUBMENU
  targets.forEach((btn) => {
    btn.addEventListener('click', () => {
      const id = btn.getAttribute('data-dd-target');
      const activePanel = navMob.querySelector(`[data-dd-panel="${id}"]`);
      if (!activePanel) return;

      gsap.set(activePanel, { x: '100%' });

      const tl = gsap.timeline();

      tl.to(main, {
        x: '-100%',
        duration: 0.35,
        ease: 'power2.out',
      });

      tl.to(
        activePanel,
        {
          x: '0%',
          duration: 0.35,
          ease: 'power2.out',
        },
        '<'
      );

      tl.to(
        inner,
        {
          height: '100%',
          duration: 0.3,
          ease: 'power2.out',
        },
        '<'
      );
    });
  });

  // BACK BUTTON
  backBtns.forEach((btn) => {
    btn.addEventListener('click', () => {
      const panel = btn.closest('[data-dd-panel]');

      const tl = gsap.timeline();

      tl.to(panel, {
        x: '100%',
        duration: 0.35,
        ease: 'power2.out',
      });

      tl.to(
        main,
        {
          x: '0%',
          duration: 0.35,
          ease: 'power2.out',
        },
        '<'
      );

      tl.to(
        inner,
        {
          height: 'auto',
          duration: 0.3,
          ease: 'power2.out',
        },
        '<'
      );
    });
  });
}

function initDropdown() {
  const navbar = document.querySelector('.navbar');
  if (!navbar) return;

  const navLinks = navbar.querySelectorAll('.nav-link.is-dropdown');

  navLinks.forEach((link) => {
    const head = link.querySelector('.nav-dd-head');
    const content = link.querySelector('.nav-dropdown');
    const block = content.querySelector('.nav-dd-block');

    if (!head || !content) return;

    // anggap satu group (link = wrapper)
    link.addEventListener('mouseenter', () => {
      // close semua dulu (biar pindah antar menu clean)
      navLinks.forEach((item) => {
        const dropdown = item.querySelector('.nav-dropdown');
        dropdown?.classList.remove('is-active');
      });

      content.classList.add('is-active');
    });

    link.addEventListener('mouseleave', () => {
      content.classList.remove('is-active');
    });
  });
}

function navMobile() {
  const navbar = document.querySelector('.navbar');
  if (!navbar) return;

  const trigger = navbar.querySelector('.hamburger');
  const navMobile = document.querySelector('.nav-mobile');

  if (!trigger || !navMobile) return;

  trigger.addEventListener('click', () => {
    const isOpen = trigger.classList.contains('is-active');

    if (isOpen) {
      trigger.classList.remove('is-active');
      navMobile.classList.remove('is-active');
    } else {
      trigger.classList.add('is-active');
      navMobile.classList.add('is-active');
    }
  });

  function lockScroll() {
    document.body.style.overflow = 'hidden';
    lenis.stop();
  }

  function unlockScroll() {
    document.body.style.overflow = '';
    lenis.start();
  }

  // Lock scroll saat nav mobile terbuka
  trigger.addEventListener('click', () => {
    if (trigger.classList.contains('is-active')) {
      lockScroll();
    } else {
      unlockScroll();
    }
  });

  // Optional: close nav mobile saat klik link di dalamnya
  navMobile.querySelectorAll('a').forEach((link) => {
    link.addEventListener('click', () => {
      trigger.classList.remove('is-active');
      navMobile.classList.remove('is-active');
      unlockScroll();
    });
  });
}

