  const lineWrap = block.querySelector('.journey-progress-wrap');
  const line = block.querySelector('.journey-progress');
  const total = items.length; // 3

  mm.add('(max-width: 767px)', () => {
    gsap.set(line, { scaleY: 0, transformOrigin: 'center top' });

    gsap.to(line, {
      scaleY: 1,
      ease: 'none',
      scrollTrigger: {
        trigger: lineWrap,
        start: 'top center',
        end: 'bottom center',
        scrub: true,
      },
    });

    items.forEach((item) => {
      const scroll = ScrollTrigger.create({
        trigger: item,
        start: 'top center',
        onEnter: () => item.classList.add('is-active'),
        onLeave: () => item.classList.remove('is-active'),
        onEnterBack: () => item.classList.add('is-active'),
        onLeaveBack: () => item.classList.remove('is-active'),
      });
    });
  });

  mm.add('(min-width: 768px)', () => {
    gsap.set(line, { scaleX: 0, transformOrigin: 'left center' });
    gsap.to(line, {
      scaleX: 1,
      ease: 'none',
      scrollTrigger: {
        trigger: block,
        start: 'top top',
        end: 'bottom bottom',
        scrub: true,
        markers: false,
        onUpdate: (self) => {
          const progress = self.progress; // 0 to 1

          const thresholds = [0, 0.35, 0.7];

          items.forEach((item, index) => {
            if (progress >= thresholds[index]) {
              item.classList.add('is-active');
            } else {
              item.classList.remove('is-active');
            }
          });
        },
      },
    });
  });

